const allRows = $input.all();
const today = new Date();
today.setHours(0, 0, 0, 0);

const THREE_DAYS_MS = 3 * 24 * 60 * 60 * 1000;

const leadsToFollowUp = allRows.filter(function(row) {
  const status = (row.json['status'] || '').trim();
  const response = (row.json['Response'] || '').trim();
  const firstContactRaw = (row.json['First Contact Date'] || '').trim();

  // Only process leads that have been contacted but not replied
  if (status !== 'Messaged') return false;

  // Skip if they have already responded
  if (response !== '') return false;

  // Skip if no contact date logged
  if (!firstContactRaw) return false;

  // Parse the contact date — expects DD/MM/YYYY or YYYY-MM-DD
  let contactDate;
  if (firstContactRaw.includes('/')) {
    const parts = firstContactRaw.split('/');
    if (parts.length === 3) {
      // DD/MM/YYYY
      contactDate = new Date(parts[2], parts[1] - 1, parts[0]);
    }
  } else {
    contactDate = new Date(firstContactRaw);
  }

  if (!contactDate || isNaN(contactDate.getTime())) return false;

  contactDate.setHours(0, 0, 0, 0);
  const daysSinceContact = (today - contactDate) / (24 * 60 * 60 * 1000);

  // Flag if 3 or more days have passed
  return daysSinceContact >= 3;
});

console.log('Leads needing follow-up: ' + leadsToFollowUp.length + ' of ' + allRows.length + ' total rows');

return leadsToFollowUp.map(function(item) {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const firstContactRaw = (item.json['First Contact Date'] || '').trim();
  let contactDate;
  if (firstContactRaw.includes('/')) {
    const parts = firstContactRaw.split('/');
    contactDate = new Date(parts[2], parts[1] - 1, parts[0]);
  } else {
    contactDate = new Date(firstContactRaw);
  }
  contactDate.setHours(0, 0, 0, 0);
  const daysSince = Math.floor((today - contactDate) / (24 * 60 * 60 * 1000));

  return {
    json: {
      row_number: item.json['row_number'],
      business_name: (item.json['Business Name'] || item.json['Instagram Handle'] || 'Unknown').trim(),
      instagram_handle: (item.json['Instagram Handle'] || '').trim(),
      industry: (item.json['Type'] || '').trim(),
      days_since_contact: daysSince,
      first_contact_date: firstContactRaw,
      step: (item.json['Step'] || '1').trim(),
      notes: (item.json['Notes'] || '').trim(),
      channel: (item.json['Channel'] || 'Instagram DM').trim()
    }
  };
});

const items = $input.all();
const date = new Date().toISOString().split('T')[0];

if (items.length === 0) {
  return [{
    json: {
      subject: 'Zizi - Follow-up check (' + date + ') — no action needed',
      body: 'Workflow 3 - Follow-Up Reminder\nDate: ' + date + '\n\nNo leads are overdue for follow-up today. All contacts are either within 3 days or have already responded.\n\nNext check: tomorrow 9am.'
    }
  }];
}

const lines = items.map(function(item, i) {
  const lead = item.json;
  const dayLabel = lead.days_since_contact === 1 ? 'day' : 'days';
  const notesLine = lead.notes ? '\n   Notes: ' + lead.notes : '';
  return (
    (i + 1) + '. ' + lead.business_name +
    (lead.instagram_handle ? ' (@' + lead.instagram_handle + ')' : '') +
    '\n   Industry: ' + (lead.industry || 'unknown') +
    '\n   Channel: ' + lead.channel +
    '\n   Step sent: ' + lead.step +
    '\n   First contacted: ' + lead.first_contact_date + ' (' + lead.days_since_contact + ' ' + dayLabel + ' ago)' +
    notesLine
  );
});

const subject = 'Zizi - ' + items.length + ' lead' + (items.length !== 1 ? 's' : '') + ' need follow-up (' + date + ')';
const body = [
  'Workflow 3 - Follow-Up Reminder',
  'Date: ' + date,
  'Leads overdue (3+ days, no reply): ' + items.length,
  '',
  '---',
  '',
  lines.join('\n\n'),
  '',
  '---',
  '',
  'ACTION FOR ZIZI:',
  'Each lead above has not replied in 3 or more days. Send a Step 2 follow-up message for each one.',
  'Use the Step 2 formula from your briefing doc.',
  'If a lead has already replied or been closed, update the status in the sheet so it stops appearing here.',
  '',
  'If you are unsure about any lead, send it to Hadi before messaging.'
].join('\n');

return [{ json: { subject: subject, body: body, count: items.length } }];
